$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_5ee406d769ac3887713d3308a0d01601'] = 'Ange antal dagar som rå PrestaShop-besöksstatistik ska sparas. Exempel: 60 betyder att modulen sparar de senaste 60 dagarna och raderar äldre poster från ps_connections, ps_connections_source och ps_connections_page. Sätt inte 1 om du inte är säker på att du inte behöver aktuell besöksstatistik.';
