$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_acbc6e359c79ace4ef9b5398148c13e2'] = 'Ange hur många huvudposter för anslutningar som får bearbetas i en intern batch. Mindre värden är säkrare på svag hosting men kräver fler cron-körningar. Större värden rensar snabbare men kan hålla databaslås längre. Rekommenderat startvärde: 1000 till 5000; öka först efter test av körtid.';
