$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_e221a5a91ea62a43adc5bb15614eb578'] = 'Ange hur många batchar som får köras under en cron-körning. Totalt möjliga raderade huvudposter per körning är ungefär Batchstorlek multiplicerat med Maximalt antal batchar. Exempel: 5000 och 10 innebär upp till cirka 50000 poster i en cron-körning. Sänk värdet om butiken blir långsam under rensningen.';
