$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_ae729759e10d7a626a8622321932a1f4'] = 'När aktiverat sparar modulen en liten daglig sammanfattning innan rå PrestaShop-statistik tas bort. Den sparar antal besök, sidvisningar, källdomän och UTM-värden. IP-adresser, fullständiga referrer-URL:er och user-agent-strängar sparas inte. Inaktivera om du endast vill radera och inte behöver historiska sammanfattningar.';
