$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_a97a6a6ab09f48206a543fdc7321bb60'] = 'Ange hur många dagar aggregerade trafikkällsammanfattningar ska finnas kvar i modultabellen. Exempel: 730 sparar cirka två år av dagliga sammanfattningar. Inställningen påverkar endast ps_jooim_dbcleaner_traffic_daily, inte PrestaShops ursprungliga statistiktabeller.';
